#include <stdio.h>
#include <stdlib.h>
#define MAX_N 1000000
#define MAX_M 300000

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int** graph = (int**)malloc(N * sizeof(int*));
        for (int i = 0; i < N; i++) {
            graph[i] = (int*)malloc(N * sizeof(int));
            for (int j = 0; j < N; j++) {
                if (i < j) {
                    graph[i][j] = 1;
                } else if (i > j) {
                    graph[i][j] = -1;
                } else {
                    graph[i][j] = 0;
                }
            }
        }
        for (int i = 0; i < M; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            x--;
            y--;
            graph[x][y] = -1;
            graph[y][x] = 1;
        }
        int result = 0;
        int firstAttack = -1;
        for (int i = 0; i < N; i++) {
            int canDefeatAll = 1;
            for (int j = 0; j < N; j++) {
                if (i != j && graph[i][j] == -1) {
                    canDefeatAll = 0;
                    break;
                }
            }
            if (canDefeatAll) {
                result = 2;
                firstAttack = i + 1;
                break;
            }
        }
        if (result == 0) {
            for (int i = 0; i < N; i++) {
                int canDefeatAllInTwoSteps = 1;
                for (int j = 0; j < N; j++) {
                    if (i != j) {
                        int canDefeatInTwoSteps = 0;
                        for (int k = 0; k < N; k++) {
                            if (graph[i][k] == 1 && graph[k][j] == 1) {
                                canDefeatInTwoSteps = 1;
                                break;
                            }
                        }
                        if (!canDefeatInTwoSteps) {
                            canDefeatAllInTwoSteps = 0;
                            break;
                        }
                    }
                }
                if (canDefeatAllInTwoSteps) {
                    result = 1;
                    break;
                }
            }
        }
        if (result == 2) {
            printf("2 %d\n", firstAttack);
        } else if (result == 1) {
            printf("1\n");
        } else {
            printf("0\n");
        }
    }
    return 0;
}

