                graph[j][k] = -1;
            } else {
                graph[j][k] = 0;
            }
        }
    }
    for (let j = 0; j < M; j++) {
        const [x, y] = readline().split(' ').map(Number);
        graph[x - 1][y - 1] = -1;
        graph[y - 1][x - 1] = 1;
    }
    let result = 0;
    let firstAttack = -1;
    for (let j = 0; j < N; j++) {
        let canDefeatAll = 1;
